/**
 * ApiService
 *
 * Fetches project data from a plain HTTP backend.
 */
export class ApiService {
  /**
   * @param {object} opts
   * @param {string} [opts.baseUrl] e.g. "http://46.225.89.136/api" (no trailing slash)
   */
  constructor({ baseUrl = 'http://46.225.89.136/api' } = {}) {
    const raw = (baseUrl ?? '').toString().trim();
    this.baseUrl = raw ? raw.replace(/\/+$/, '') : '';
  }

  async getProject(projectId) {
    if (!projectId) throw new Error('Panorama360: projectId is required');
    const base = this.baseUrl || '';
    const url = `${base}/projects/${encodeURIComponent(String(projectId))}`;
    const res = await fetch(url, { method: 'GET', headers: { Accept: 'application/json' } });
    const text = await res.text();
    let json = null;
    try {
      json = text ? JSON.parse(text) : null;
    } catch {
      json = null;
    }
    if (!res.ok) {
      const msg =
        (json && (json.message || json.error)) ? String(json.message || json.error) :
        (text ? String(text).slice(0, 500) : `${res.status} ${res.statusText}`);
      throw new Error(`Panorama360: failed to load project from API: ${msg}`);
    }
    return json;
  }
}

